// This JSX:
function App() {
  return (
    <>
      <NavBar />
      <Main />
      <Footer />
    </>
  );
}

// Produces this render tree:
// App
// ├── NavBar
// │   ├── Logo
// │   └── Link (×2)
// ├── Main
// │   ├── ArticleList
// │   │   └── Article (×N)
// │   └── Sidebar
// └── Footer

function Dashboard({ isAdmin }) {
  return (
    <main>
      <FeedPanel />
      {isAdmin && <AdminPanel />} {/* conditional — exists or not in the tree */}
    </main>
  );
}

// Render tree when isAdmin=false:
// Dashboard
// └── main (host)
//     └── FeedPanel

// Render tree when isAdmin=true:
// Dashboard
// └── main (host)
//     ├── FeedPanel
//     └── AdminPanel   ← appears; state initialized fresh

function App({ mode }) {
  // Position 0 alternates between two component types
  return mode === 'dark' ? <DarkTheme /> : <LightTheme />;
}

// When mode flips:
// React sees: old = DarkTheme, new = LightTheme
// Types differ → DarkTheme unmounts (state destroyed), LightTheme mounts fresh

// Compare this to a prop change:
function App({ color }) {
  return <ThemePanel color={color} />;  // same type every time
  // When color changes: ThemePanel re-renders, state preserved
}

// Leaf component — returns only host elements
function Article({ title, body, publishedAt }) {
  return (
    <article>
      <h2>{title}</h2>
      <p>{body}</p>
      <time>{publishedAt}</time>
    </article>
  );
}

// Internal node — renders other custom components
function ArticleList({ articles }) {
  return (
    <ul>
      {articles.map(a => (
        <Article key={a.id} title={a.title} body={a.body} publishedAt={a.date} />
      ))}
    </ul>
  );
}

// Two independent render trees on the same page
const root1 = createRoot(document.getElementById('app'));
root1.render(<App />);

const root2 = createRoot(document.getElementById('widget'));
root2.render(<Widget />);
// App and Widget are roots of separate render trees.

import { createPortal } from 'react-dom';

function Modal({ children, isOpen }) {
  if (!isOpen) return null;
  // Render tree: Modal is still a child of whatever renders it
  // DOM tree: children are placed under document.body
  return createPortal(
    <div className="modal">{children}</div>,
    document.body
  );
}

// WRONG: Inner is a new function on every Parent render
function Parent() {
  function Inner() {              // new reference every render
    const [x, setX] = useState(0);
    return <button onClick={() => setX(x + 1)}>{x}</button>;
  }
  return <Inner />;               // unmounts and remounts every time!
}

// CORRECT: define at module scope
function Inner() {                // stable reference
  const [x, setX] = useState(0);
  return <button onClick={() => setX(x + 1)}>{x}</button>;
}
function Parent() {
  return <Inner />;               // same type every render — state preserved
}

function LoginForm({ step }) {
  return (
    <form>
      {step === 1 && <EmailStep />}  {/* appears/disappears */}
      {step === 2 && <PasswordStep />}  {/* same position as EmailStep! */}
    </form>
  );
}

// When step goes 1 -> 2:
// Position 0: EmailStep unmounts, PasswordStep mounts
// Both share position 0 in the tree but have different types
// State is NOT shared between them

// Contrast: same type, different position
function Steps() {
  return (
    <>
      {step >= 1 && <Step num={1} />}  {/* position 0 */}
      {step >= 2 && <Step num={2} />}  {/* position 1 — new mount */}
    </>
  );
}

function TaskList({ tasks }) {
  return (
    <ul>
      {tasks.map(task => (
        // Each <TaskItem> is a node in the render tree at this position
        // The key tells React which node corresponds to which task
        <TaskItem key={task.id} task={task} />
      ))}
    </ul>
  );
}

// Render tree for tasks = [A, B, C]:
// TaskList
// └── ul (host)
//     ├── TaskItem (key=A)
//     ├── TaskItem (key=B)
//     └── TaskItem (key=C)

// After removing B (tasks = [A, C]):
// TaskItem(key=B) unmounts; TaskItem(key=A) and (key=C) re-render but keep state

const ThemeContext = createContext("light");

function App() {
  return (
    // ThemeContext.Provider at the root of the render tree
    <ThemeContext.Provider value="dark">
      <Page />
    </ThemeContext.Provider>
  );
}

function Page() {
  return <Section />;
}

function Section() {
  return <Article />;
}

function Article() {
  // Reads from context — no props needed at intermediate levels
  const theme = useContext(ThemeContext); // "dark"
  return <div className={theme}>...</div>;
}

function App() {
  return (
    <Suspense fallback={<Spinner />}>
      {/* Render tree subtree that may suspend */}
      <LazyDashboard />
    </Suspense>
  );
}

// If LazyDashboard suspends while loading:
// React replaces the entire Suspense subtree with <Spinner />
// When the data/code arrives, React replaces <Spinner /> with <LazyDashboard />

class ErrorBoundary extends React.Component {
  state = { hasError: false };

  static getDerivedStateFromError() {
    return { hasError: true };
  }

  render() {
    if (this.state.hasError) {
      return <div>Something went wrong.</div>;
    }
    return this.props.children;
  }
}

function App() {
  return (
    <ErrorBoundary>
      <RiskyFeature />
    </ErrorBoundary>
  );
}
